+
+[execution]
+type = "exec-wrapper"
+wrapper = ["exitbox", "run", "--"]
++++
+
+# Sandbox
+`), 0644); err != nil {
+		t.Fatalf("failed to write: %v", err)
+	}
+
+	scanner := NewScanner(tmpDir, nil)
+
+	// DiscoverAll should find both
+	all, err := scanner.DiscoverAll()
+	if err != nil {
+		t.Fatalf("DiscoverAll failed: %v", err)
+	}
+	if len(all) != 2 {
+		t.Errorf("expected 2 plugins, got %d", len(all))
